  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = \"file:./dev.db\"\n}\n\n// ---------------------------\n// 1. UTILISATEURS & PERSONNEL\n// ---------------------------\n\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  role      String   @default(\"PARENT\") // ADMIN, TEACHER, STAFF, PARENT, STUDENT\n  firstName String\n  lastName  String\n  phone     String?\n  avatarUrl String?\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  studentProfile Student?\n  teacherProfile Teacher?\n  parentProfile  Parent?\n}\n\n// Enum Role removed for SQLite compatibility\n\nmodel Parent {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Peut avoir plusieurs enfants\n  students Student[]\n}\n\nmodel Teacher {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  specialty String?\n\n  // Relations\n  classes    Class[] // Classes dirigées\n  courses    Course[] // Cours enseignés\n  attendance Attendance[] // Validation d'absences\n}\n\n// ---------------------------\n// 2. ÉLÈVES & INSCRIPTIONS\n// ---------------------------\n\nmodel Student {\n  id     String  @id @default(uuid())\n  userId String? @unique\n  user   User?   @relation(fields: [userId], references: [id])\n\n  enrollmentId String   @unique // Matricule scolaire\n  dateOfBirth  DateTime\n  gender       String\n  address      String?\n  medicalInfo  String? // Allergies, etc.\n\n  // Relation avec les parents\n  parentId String?\n  parent   Parent? @relation(fields: [parentId], references: [id])\n\n  classId String?\n  class   Class?  @relation(fields: [classId], references: [id])\n\n  grades       Grade[]\n  attendances  Attendance[]\n  behaviorLogs BehaviorLog[]\n  payments     Payment[]\n\n  createdAt DateTime @default(now())\n}\n\n// ---------------------------\n// 3. ACADÉMIQUE\n// ---------------------------\n\nmodel Class {\n  id       String @id @default(uuid())\n  name     String // ex: 6ème A, 1ère S\n  level    String // Primaire, Collège, etc.\n  capacity Int\n\n  teacherId String? // Professeur principal\n  teacher   Teacher? @relation(fields: [teacherId], references: [id])\n\n  students Student[]\n  courses  Course[]\n}\n\nmodel Course {\n  id          String  @id @default(uuid())\n  name        String // Mathématiques, Histoire...\n  description String?\n\n  teacherId String\n  teacher   Teacher @relation(fields: [teacherId], references: [id])\n\n  classId String\n  class   Class  @relation(fields: [classId], references: [id])\n\n  grades   Grade[]\n  schedule Schedule[]\n}\n\nmodel Schedule {\n  id       String @id @default(uuid())\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id])\n\n  dayOfWeek Int // 1 (Lundi) à 7 (Dimanche)\n  startTime String // Ex: 08:00\n  endTime   String // Ex: 10:00\n  room      String? // Salle C12\n}\n\nmodel Grade {\n  id       String  @id @default(uuid())\n  score    Float\n  maxScore Float   @default(20)\n  term     String // Trimestre 1, Semestre 1...\n  comments String?\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id])\n  courseId  String\n  course    Course  @relation(fields: [courseId], references: [id])\n\n  createdAt DateTime @default(now())\n}\n\nmodel Attendance {\n  id     String   @id @default(uuid())\n  date   DateTime\n  status String // PRESENT, ABSENT, LATE, EXCUSED\n  notes  String?\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id])\n\n  teacherId String?\n  teacher   Teacher? @relation(fields: [teacherId], references: [id])\n}\n\n// Enum AttendanceStatus removed\n\n// ---------------------------\n// 4. DISCIPLINE & COMPORTEMENT\n// ---------------------------\n\nmodel BehaviorLog {\n  id          String   @id @default(uuid())\n  date        DateTime @default(now())\n  title       String\n  description String\n  type        String // POSITIVE, NEGATIVE, WARNING\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id])\n}\n\n// Enum BehaviorType removed\n\n// ---------------------------\n// 5. FINANCE (PAIEMENTS)\n// ---------------------------\n\nmodel Payment {\n  id          String    @id @default(uuid())\n  amount      Float\n  currency    String    @default(\"EUR\")\n  status      String    @default(\"PENDING\")\n  description String // Ex: Frais de scolarité Trimestre 1\n  dueDate     DateTime\n  paidDate    DateTime?\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id])\n}\n\n// Enum PaymentStatus removed\n",
